import { Dropdown, Menu, Table, TableProps, Modal } from 'antd'
import { User } from "types/user";
import dayjs from "dayjs";
import {Link} from 'react-router-dom'
import { Pin } from 'components/pin';
import { useDeleteProject, useEditProject } from 'utils/project';
import { ButtonNoPadding } from 'components/lib';
import { useProjectModal, useProjectsQueryKey } from './util';
import { Project } from 'types/project'

interface ListProps extends TableProps<Project>{
	users: User[]
} 

export const List = ({ users, ...props}: ListProps) => {
  
  const {mutate} = useEditProject(useProjectsQueryKey())
  
  const pinProject = (id: number) => (pin:boolean) => mutate({id, pin}) // 函数柯理化
  
	return <Table pagination={false} columns={[
      {
        title: <Pin checked={true} disabled={true} />,
        render(value, project) {
          return <Pin checked={project.pin} onCheckedChange={pinProject(project.id)} />
        }
      },
			{ title: '名称', dataIndex: 'name',sorter: (a,b)=> a.name.localeCompare(b.name), render(value, project) {
        return <Link to={`${project.id}`}>{project.name}</Link>
      } },
			{ title: '部门', dataIndex: 'organization' },
			{ title: '负责人', render (value, project) {
    return <span>{users.find((user) => user.id === project.personId)?.name || "/"}</span>
  } },
			{title: '创建时间', render (value, project) {
				return <span>{project.created && dayjs(project.created).format('YYYY-MM-DD HH:mm:ss')}</span>
	}},{
    render (value, project) {
      return <More project={project} />
    }
  }

  ]} {...props} />
}

const More = ({project}: {project: Project}) => {
  const {startEdit} = useProjectModal()
  const { mutate: deleteMutate } = useDeleteProject(useProjectsQueryKey())
  const editPorject = (id: number) => () => startEdit(id)
  const confirmDeleteProject = (id: number) => () => {
    Modal.confirm({
      title: '删除项目',
      content: '确认删除当前项目',
      okText:'删除',
      cancelText:'取消',
      onOk: () => deleteMutate({id})
    })
  }

  return <Dropdown overlay={<Menu>
    <Menu.Item key={'edit'}>
      <ButtonNoPadding type={'link'} onClick={editPorject(project.id)}>编辑</ButtonNoPadding>
    </Menu.Item>
    <Menu.Item key={'del'}>
    <ButtonNoPadding type={'link'} onClick={confirmDeleteProject(project.id)}>删除</ButtonNoPadding>
    </Menu.Item>
  </Menu>}>
    <ButtonNoPadding type={'link'}>...</ButtonNoPadding>
  </Dropdown>
}