import { useDocumentTitle } from 'utils'
import { useKanbanInProject, useKanbansQueryKey, useProjectInUrl, useTasksInProject, useTasksQueryKey, useTasksSearchParams } from './util'
import { KanbanColumn } from './kanban-column'
import styled from '@emotion/styled'
import { SearchPanel } from './search-panel'
import { ScreenContainer } from 'components/lib'
import { useReorderTask, useTasks } from 'utils/task'
import { Spin } from 'antd'
import { CreateKanban } from './create-kanban'
import { TaskModal } from './task-modal'
import { DragDropContext, DropResult } from 'react-beautiful-dnd'
import { Drag, Drop, DropChild } from 'components/drag-and-drop'
import { useReorderKanban } from 'utils/kanban'
import { useCallback } from 'react'

export const KanbanScreen = () => {
  useDocumentTitle('看板列表')
  const { data: kanbans } = useKanbanInProject()
  const { data: currentProject, isLoading: kanbanIsLoading } = useProjectInUrl()
  const { isLoading: taskIsLoading } = useTasks(useTasksSearchParams())
  const onDragEnd = useDragEnd()
  const isLoading = taskIsLoading || kanbanIsLoading
  return <DragDropContext onDragEnd={onDragEnd}>
    <ScreenContainer>
      <h1>{currentProject?.name}看板</h1>
      <SearchPanel />
      {
        isLoading ? <Spin size='large' /> : <ColumnsCotainer>
          <Drop type='COLUMN' direction='horizontal' droppableId='kanban'>
            <DropChild style={{display: 'flex'}}>
              {
                kanbans?.map((kanban, index) => <Drag index={index} key={kanban.id} draggableId={'kanban' + kanban.id}><KanbanColumn kanban={kanban} /></Drag>)
              }
            </DropChild>
          </Drop>
          <CreateKanban />
        </ColumnsCotainer>
      }
      <TaskModal />
    </ScreenContainer>
  </DragDropContext>
}

export const useDragEnd = () => {
  const {data: kanbans} = useKanbanInProject()
  const {mutate: sortTask} = useReorderTask(useTasksQueryKey())
  const {mutate: sortKanban} = useReorderKanban(useKanbansQueryKey())
  const { data: allTasks } = useTasksInProject()
  return useCallback(
    ({source, destination, type}: DropResult) => {
      if (!destination) return
      // 看板排序
      if (type === 'COLUMN') {
        const fromId = kanbans?.[source.index].id
        const toId = kanbans?.[destination.index].id
        if (!fromId || !toId || fromId === toId) return
        const type = destination.index > source.index ? 'after' : 'before'
        sortKanban({fromId, referenceId: toId, type})
      } else if(type === 'ROW') {
        const fromKanbanId = +source.droppableId
        const toKanbanId = +destination.droppableId
        // if (fromKanbanId !== toKanbanId) {
        //   return
        // }
        const fromTask = allTasks?.filter(task => task.kanbanId === fromKanbanId)[source.index]
        const toTask = allTasks?.filter(task => task.kanbanId === toKanbanId)[destination.index]
        if (!fromTask?.id || !toTask?.id || fromTask?.id === toTask?.id ) return
        const type = destination.index > source.index ? 'after' : 'before'
        sortTask({fromId:fromTask.id, referenceId: toTask.id, fromKanbanId, toKanbanId, type})
      }
    },
    [allTasks, kanbans, sortKanban, sortTask],
  )
}

export const ColumnsCotainer = styled('div')`
  display: flex;
  flex: 1;
  overflow-x: auto;
`