import { Kanban } from "types/kanban";
import { useTaskTypes } from "utils/task-type";
import {
  useKanbansQueryKey,
  useTasksInProject,
  useTasksModal,
  useTasksSearchParams,
} from "./util";
import taskIcon from "assets/task.svg";
import bugIcon from "assets/bug.svg";
import styled from "@emotion/styled";
import { Button, Card, Dropdown, Menu, Modal } from "antd";
import { CreateTask } from "./create-task";
import { Task } from "types/task";
import { Mark } from "components/mark";
import { useDeleteKanban } from "utils/kanban";
import { Row } from "components/lib";
import React from 'react';
import { Drag, Drop, DropChild } from 'components/drag-and-drop';

const TaskTypeIcon = ({ id }: { id: number }) => {
  const { data: taskTypes } = useTaskTypes();
  const name = taskTypes?.find((taskType) => taskType.id === id)?.name;
  if (!name) return null;
  return <img alt="任务类型图标" src={name === "task" ? taskIcon : bugIcon} />;
};

const TaskCard = ({ task }: { task: Task }) => {
  const { startEdit } = useTasksModal();
  const { name: keyword } = useTasksSearchParams();
  return (
    <MeCard onClick={() => startEdit(task.id)} key={task.id}>
      <Mark name={task.name} keyword={keyword} />
      <p>
        <TaskTypeIcon id={task.typeId} />
      </p>
    </MeCard>
  );
};

const More = ({ kanban }: { kanban: Kanban }) => {
  const { mutateAsync: deleteKanban } = useDeleteKanban(useKanbansQueryKey());
  const startDel = () => {
    Modal.confirm({
      title: '删除当前看板',
      content: '是否确认删除当前看板',
      okText: '确认',
      cancelText: '取消',
      onOk () {
        deleteKanban({id: kanban.id})
      }
    })
  }
  const overlay = (
    <Menu>
      <Menu.Item>
        <Button type='link' onClick={startDel}>删除</Button>
      </Menu.Item>
    </Menu>
  );
  return (
    <Dropdown overlay={overlay}>
      <Button type="link">...</Button>
    </Dropdown>
  );
};

export const KanbanColumn = React.forwardRef<HTMLDivElement, { kanban: Kanban }>(({kanban, ...props}, ref) => {
  const { data: allTasks } = useTasksInProject();
  const tasks = allTasks?.filter((task) => task.kanbanId === kanban.id);

  return (
    <Container ref={ref} {...props}>
      <Row between>
        <h3>{kanban.name}</h3>
        <More kanban={kanban} key={kanban.id} />
      </Row>

      <TaskContainer>
        <Drop type="ROW" direction='vertical' droppableId={String(kanban.id)}>
          <DropChild style={{minHeight: '5px'}}>
            {
              tasks?.map((task, index) => (
                <Drag key={task.id} index={index} draggableId={'task' + task.id}>
                  <div>
                    <TaskCard task={task} />
                  </div>
                </Drag>
              ))
            }
          </DropChild>
        </Drop>
        <CreateTask kanbanId={kanban.id} />
      </TaskContainer>
    </Container>
  );
})

const MeCard = styled(Card)`
  margin-bottom: 0.5rem;
  cursor: pointer;
`;

export const Container = styled.div`
  min-width: 27rem;
  border-radius: 6px;
  background-color: rgb(244, 245, 247);
  display: flex;
  flex-direction: column;
  padding: 0.7rem 0.7rem 1rem;
  margin-right: 1.5rem;
`;

const TaskContainer = styled.div`
  overflow: scroll;
  flex: 1;
  ::-webkit-scrollbar {
    display: none;
  }
`;