import { Button, Input } from 'antd'
import { Row } from 'components/lib'
import { TaskTypeSelect } from 'components/task-type-select'
import { UserSelect } from 'components/user-select'
import { useSetUrlSearchParams } from 'utils/url'
import { useTasksSearchParams } from './util'

export const SearchPanel = ()  => {
  const searchParams  = useTasksSearchParams()
  const setSearchParams = useSetUrlSearchParams()
  const reset = () => setSearchParams({
    typeId: undefined,
    tagId: undefined,
    processorId: undefined,
    name: undefined,  
  })

  return <Row marginBottom={3} gap={true}>
    <Input style={{width: '20rem'}} placeholder={'任务名'} value={searchParams.name} onChange={(EventTarget) => setSearchParams({name: EventTarget.target.value})} />
    <UserSelect defaultOptionName={'经办人'} value={searchParams.processorId} onChange={value => setSearchParams({processorId: value})} />
    <TaskTypeSelect defaultOptionName={'任务类型'} value={searchParams.typeId} onChange={value => setSearchParams({typeId: value})} />
    <Button type={'primary'} onClick={reset}>重置</Button>
  </Row>
}