import styled from '@emotion/styled'
import { Button, Drawer, Form, Input, Spin } from 'antd'
import { useForm } from 'antd/lib/form/Form'
import { ErrorBox } from 'components/lib'
import { UserSelect } from 'components/user-select'
import { useEffect } from 'react'
import { useProjectModal, useProjectsQueryKey } from 'screens/project-list/util'
import { useAddProject, useEditProject } from 'utils/project'

export const ProjectModal = () => {
  const {projectModalOpen, close, editingProject, isLoading} = useProjectModal()
  const tilte = editingProject ? '编辑项目':'新增项目'

  const useMutateProject = editingProject ? useEditProject : useAddProject
  const {mutateAsync, error, isLoading: mutateLoading} = useMutateProject(useProjectsQueryKey())
  const [form] = useForm()
  const onFinish = (values: any) => {
    mutateAsync({...editingProject, ...values}).then(() => {
      form.resetFields()
      close()
    })
  }
  const closeModal = () => {
    form.resetFields()
    close()
  }

  useEffect(() => {
    form.setFieldsValue(editingProject)
  }, [editingProject, form])

	return (
		<Drawer forceRender={true} onClose={closeModal} visible={projectModalOpen} width={'100%'}>
      <Container>
      {
        isLoading ? <Spin size={'large'} /> : <>
          <h1>{tilte}</h1>
          <ErrorBox error={error} />
          <Form form={form} layout={'vertical'} style={{width: '40rem'}} onFinish={onFinish} >
            <Form.Item label={'名称'} name={'name'} rules={[{required:  true, message: '请输入项目名称'}]}>
              <Input placeholder={'请输入项目名称'} />
            </Form.Item>
            <Form.Item label={'部门'} name={'organization'} rules={[{required:  true, message: '请输入部门'}]}>
              <Input placeholder={'请输入部门'} />
            </Form.Item>
            <Form.Item label={'负责人'} name={'personId'} >
              <UserSelect defaultOptionName={'负责人'} />
            </Form.Item>
            <Form.Item style={{textAlign: 'center'}}>
              <Button loading={mutateLoading} type={'primary'} htmlType={'submit'}>提交</Button>
            </Form.Item>
          </Form>
        </>
      }
			{/* <h1>Project Modal</h1>
			<Button onClick={close}>关闭</Button> */}
      </Container>
		</Drawer>
	)
}

const Container = styled.div`
  height: 80vh;
  display: flex;
  justify-content: center;
  align-items: center;
  flex-direction: column;
`